import type { SudokuBoard } from '@algorithm.ts/sudoku'
import { SudokuCreator } from '@kyokuya-demo/util/sudoku'

const creators: Record<number, SudokuCreator> = {}

/**
 * Get sudoku creator
 * @param SUDOKU_SIZE_SQRT
 * @returns
 */
export const getSudokuCreator = (SUDOKU_SIZE_SQRT: number): SudokuCreator => {
  let creator = creators[SUDOKU_SIZE_SQRT]
  if (creator === undefined) {
    creator = new SudokuCreator({ childMatrixSize: SUDOKU_SIZE_SQRT })
    creators[SUDOKU_SIZE_SQRT] = creator
  }
  return creator
}

/**
 * Check if the puzzle solved.
 * @param SUDOKU_SIZE
 * @param attempt
 * @param solution
 * @returns
 */
export const checkCompleted = (
  SUDOKU_SIZE: number,
  attempt: Readonly<SudokuBoard>,
  solution: Readonly<SudokuBoard>,
): boolean => {
  for (let r = 0; r < SUDOKU_SIZE; ++r) {
    for (let c = 0; c < SUDOKU_SIZE; ++c) {
      if (attempt[r][c] !== solution[r][c]) return false
    }
  }
  return true
}
