/* eslint-disable no-param-reassign */
import type { SudokuBoard } from '@algorithm.ts/sudoku'

const lastPosOfValue: number[] = []

/**
 * Create a two-dimension boolean array, which indicated whether if the content
 * of a cell is break the number-unique rules.
 * @param SUDOKU_SIZE
 * @returns
 */
export const createDuplicatedMap = (SUDOKU_SIZE: number): boolean[][] => {
  const duplicatedMap: boolean[][] = new Array(SUDOKU_SIZE)
  for (let r = 0; r < SUDOKU_SIZE; ++r) {
    duplicatedMap[r] = new Array(SUDOKU_SIZE).fill(false)
  }
  return duplicatedMap
}

/**
 * Clear duplicated map.
 *
 * @param SUDOKU_SIZE
 * @param duplicatedMap
 */
export const clearDuplicatedMap = (duplicatedMap: boolean[][]): void => {
  for (const h of duplicatedMap) h.fill(false)
}

/**
 * Find grids which has a duplicated number on the same row, the same column or
 * the same sub-child matrix.
 *
 * @param SUDOKU_SIZE_SQRT
 * @param attempt
 * @param duplicatedMap
 */
export const initDuplicatedMap = (
  SUDOKU_SIZE_SQRT: number,
  attempt: Readonly<SudokuBoard>,
  duplicatedMap: boolean[][],
): void => {
  const SUDOKU_SIZE = SUDOKU_SIZE_SQRT

  // Initialize.
  for (let r = 0; r < SUDOKU_SIZE; ++r) duplicatedMap[r].fill(false)
  if (lastPosOfValue.length < SUDOKU_SIZE) lastPosOfValue.length = SUDOKU_SIZE

  // Scan rows.
  for (let r = 0; r < SUDOKU_SIZE; ++r) {
    lastPosOfValue.fill(-1, 0, SUDOKU_SIZE)
    for (let c = 0; c < SUDOKU_SIZE; ++c) {
      const v = attempt[r][c]
      if (v === -1) continue

      const c0 = lastPosOfValue[v]
      if (c0 !== -1) duplicatedMap[r][c0] = duplicatedMap[r][c] = true
      lastPosOfValue[v] = c
    }
  }

  // Scan columns.
  for (let c = 0; c < SUDOKU_SIZE; ++c) {
    lastPosOfValue.fill(-1, 0, SUDOKU_SIZE)
    for (let r = 0; r < SUDOKU_SIZE; ++r) {
      const v = attempt[r][c]
      if (v === -1) continue

      const r0 = lastPosOfValue[v]
      if (r0 !== -1) duplicatedMap[r0][c] = duplicatedMap[r][c] = true
      lastPosOfValue[v] = r
    }
  }

  // Scan sub-child matrix.
  for (let x = 0; x < SUDOKU_SIZE_SQRT; ++x) {
    for (let y = 0; y < SUDOKU_SIZE_SQRT; ++y) {
      lastPosOfValue.fill(-1, 0, SUDOKU_SIZE)
      for (let a = 0; a < SUDOKU_SIZE_SQRT; ++a) {
        const r = x * SUDOKU_SIZE_SQRT + a
        for (let b = 0; b < SUDOKU_SIZE_SQRT; ++b) {
          const c = y * SUDOKU_SIZE_SQRT + b
          const v = attempt[r][c]
          if (v === -1) continue

          const s0 = lastPosOfValue[v]
          if (s0 !== -1) {
            duplicatedMap[s0 >> 16][s0 & 0xffff] = duplicatedMap[r][c] = true
          }
          lastPosOfValue[v] = (r << 16) | c
        }
      }
    }
  }
}

/**
 * Re-check the all grids in the row, column, and sub-square matrix of the given
 * grid.
 *
 * @param duplicatedMap
 * @param SUDOKU_SIZE_SQRT
 * @param _r
 * @param _c
 * @param attempt
 * @param segmentNoMap
 */
export const patchDuplicatedMap = (
  _r: number,
  _c: number,
  duplicatedMap: boolean[][],
  SUDOKU_SIZE_SQRT: number,
  attempt: Readonly<SudokuBoard>,
  segmentNoMap: ReadonlyArray<number>,
): void => {
  const SUDOKU_SIZE = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT
  const sr = segmentNoMap[_r] * SUDOKU_SIZE_SQRT
  const sc = segmentNoMap[_c] * SUDOKU_SIZE_SQRT

  // Initialize.
  if (lastPosOfValue.length < SUDOKU_SIZE) lastPosOfValue.length = SUDOKU_SIZE

  for (let i = 0; i < SUDOKU_SIZE; ++i) {
    duplicatedMap[_r][i] = duplicatedMap[i][_c] = false
  }
  for (let i = 0, scEnd = sc + SUDOKU_SIZE_SQRT; i < SUDOKU_SIZE_SQRT; ++i) {
    duplicatedMap[sr + i].fill(false, sc, scEnd)
  }

  // Scan row.
  lastPosOfValue.fill(-1, 0, SUDOKU_SIZE)
  for (let i = 0; i < SUDOKU_SIZE; ++i) {
    const v = attempt[_r][i]
    if (v === -1) continue

    const c0 = lastPosOfValue[v]
    if (c0 !== -1) duplicatedMap[_r][c0] = duplicatedMap[_r][i] = true
    lastPosOfValue[v] = i
  }

  // Scan column
  lastPosOfValue.fill(-1, 0, SUDOKU_SIZE)
  for (let i = 0; i < SUDOKU_SIZE; ++i) {
    const v = attempt[i][_c]
    if (v === -1) continue

    const r0 = lastPosOfValue[v]
    if (r0 !== -1) duplicatedMap[r0][_c] = duplicatedMap[i][_c] = true
    lastPosOfValue[v] = i
  }

  // Scan sub-child matrix.
  lastPosOfValue.fill(-1, 0, SUDOKU_SIZE)
  for (let a = 0; a < SUDOKU_SIZE_SQRT; ++a) {
    const r = sr + a
    for (let b = 0; b < SUDOKU_SIZE_SQRT; ++b) {
      const c = sc + b
      const v = attempt[r][c]
      if (v === -1) continue

      const s0 = lastPosOfValue[v]
      if (s0 !== -1) {
        duplicatedMap[s0 >> 16][s0 & 0xffff] = duplicatedMap[r][c] = true
      }
      lastPosOfValue[v] = (r << 16) | c
    }
  }
}
