import type { IKyokuyaSudokuState } from './state'

export enum KyokuyaSudokuActionType {
  // Restart game.
  RESTART = '@kyokuya/sudoku/restart',

  // Reset game.
  RESET = '@kyokuya/sudoku/reset',

  // Start game.
  START = '@kyokuya/sudoku/start',

  // Pause game.
  PAUSE = '@kyokuya/sudoku/pause',

  // Resume game.
  RESUME = '@kyokuya/sudoku/resume',

  // Game finished.
  FINISHED = '@kyokuya/sudoku/finished',

  // CHANGE the activated board cell.
  ACTIVE = '@kyokuya/sudoku/active',

  // Asking for a hint.
  HINT = '@kyokuya/sudoku/hint',

  // Input into a board cell.
  INPUT = '@kyokuya/sudoku/input',
}

export type IKyokuyaSudokuAction =
  | {
      type: KyokuyaSudokuActionType.RESTART
    }
  | {
      type: KyokuyaSudokuActionType.RESET
      payload: {
        difficulty?: IKyokuyaSudokuState['difficulty']
        SUDOKU_SIZE_SQRT?: IKyokuyaSudokuState['SUDOKU_SIZE_SQRT']
        radix?: IKyokuyaSudokuState['radix']
      }
    }
  | {
      type: KyokuyaSudokuActionType.START
    }
  | {
      type: KyokuyaSudokuActionType.PAUSE
    }
  | {
      type: KyokuyaSudokuActionType.RESUME
    }
  | {
      type: KyokuyaSudokuActionType.FINISHED
      payload: number // score
    }
  | {
      type: KyokuyaSudokuActionType.ACTIVE
      payload: { r: number; c: number }
    }
  | {
      type: KyokuyaSudokuActionType.HINT
    }
  | {
      type: KyokuyaSudokuActionType.INPUT
      payload: number
    }
