import type { SudokuBoard } from '@algorithm.ts/sudoku'
import {
  copySudokuBoard,
  createSegmentCodeMap,
  createSudokuBoard,
} from '@algorithm.ts/sudoku'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import type React from 'react'
import {
  clearDuplicatedMap,
  createDuplicatedMap,
  patchDuplicatedMap,
} from '../util/duplicated'
import { findCandidateHintCell } from '../util/hint'
import { getSudokuCreator } from '../util/sudoku'
import type { IKyokuyaSudokuAction } from './action'
import { KyokuyaSudokuActionType } from './action'
import type { IKyokuyaSudokuState } from './state'

export const reducer: React.Reducer<
  IKyokuyaSudokuState,
  IKyokuyaSudokuAction
> = (
  state: IKyokuyaSudokuState,
  action: IKyokuyaSudokuAction,
): IKyokuyaSudokuState => {
  switch (action.type) {
    case KyokuyaSudokuActionType.RESTART: {
      const { SUDOKU_SIZE_SQRT, difficulty, attempt, duplicatedMap } = state

      const creator = getSudokuCreator(SUDOKU_SIZE_SQRT)
      const { puzzle, solution } = creator.createSudoku(difficulty)

      // initialize.
      copySudokuBoard(puzzle, attempt as SudokuBoard)
      clearDuplicatedMap(duplicatedMap as boolean[][])

      return {
        ...state,
        gameStatus: GameRunningStatus.PENDING,
        gameTick: state.gameTick + 1,
        puzzle,
        solution,
        hintCell: { r: -1, c: -1, v: -1 },
        hintTick: 0,
        attemptTick: 0,
      }
    }
    case KyokuyaSudokuActionType.RESET: {
      const {
        difficulty = state.difficulty,
        SUDOKU_SIZE_SQRT = state.SUDOKU_SIZE_SQRT,
        radix = state.radix,
      } = action.payload

      // It's only necessary to regenerate the data if the the difficulty
      // or size changed,
      if (
        difficulty === state.difficulty &&
        SUDOKU_SIZE_SQRT === state.SUDOKU_SIZE_SQRT
      ) {
        return radix === state.radix ? state : { ...state, radix }
      }

      const SUDOKU_SIZE = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT
      const creator = getSudokuCreator(SUDOKU_SIZE_SQRT)
      const { puzzle, solution } = creator.createSudoku(difficulty / 100)

      let attempt = state.attempt
      let segmentNoMap = state.segmentNoMap
      let duplicatedMap = state.duplicatedMap

      if (SUDOKU_SIZE_SQRT === state.SUDOKU_SIZE_SQRT) {
        clearDuplicatedMap(state.duplicatedMap as boolean[][])
        copySudokuBoard(puzzle, attempt as SudokuBoard)
      } else {
        attempt = createSudokuBoard(SUDOKU_SIZE)
        segmentNoMap = createSegmentCodeMap(SUDOKU_SIZE_SQRT)
        duplicatedMap = createDuplicatedMap(SUDOKU_SIZE)
        copySudokuBoard(puzzle, attempt as SudokuBoard)
      }

      return {
        SUDOKU_SIZE_SQRT,
        difficulty,
        radix,
        gameStatus: GameRunningStatus.PENDING,
        score: state.score,
        puzzle,
        solution,
        attempt,
        segmentNoMap,
        duplicatedMap,
        activatedCell: state.activatedCell,
        hintCell: { r: -1, c: -1, v: -1 },
        gameTick: state.gameTick + 1,
        attemptTick: 0,
        hintTick: 0,
      }
    }
    case KyokuyaSudokuActionType.START: {
      // Not in pending state.
      if (state.gameStatus !== GameRunningStatus.PENDING) return state
      return { ...state, gameStatus: GameRunningStatus.RUNNING }
    }
    case KyokuyaSudokuActionType.PAUSE: {
      // Not in running state.
      if (state.gameStatus !== GameRunningStatus.RUNNING) return state
      return { ...state, gameStatus: GameRunningStatus.PAUSED }
    }
    case KyokuyaSudokuActionType.RESUME: {
      // Not in paused state.
      if (state.gameStatus !== GameRunningStatus.PAUSED) return state
      return { ...state, gameStatus: GameRunningStatus.RUNNING }
    }
    case KyokuyaSudokuActionType.FINISHED: {
      // Not in running state.
      if (state.gameStatus !== GameRunningStatus.RUNNING) return state
      const score = Math.round(action.payload)
      return {
        ...state,
        gameStatus: GameRunningStatus.FINISHED,
        score: state.score + Math.max(0, score),
      }
    }
    case KyokuyaSudokuActionType.ACTIVE: {
      const { r, c } = action.payload
      const { activatedCell } = state
      if (activatedCell.r === r && activatedCell.c === c) return state
      return { ...state, activatedCell: { r, c } }
    }
    case KyokuyaSudokuActionType.HINT: {
      const { SUDOKU_SIZE_SQRT, puzzle, solution, attempt, activatedCell } =
        state

      // Prefer current activated cell.
      const hintCell =
        activatedCell.r > -1 && puzzle[activatedCell.r][activatedCell.c] === -1
          ? activatedCell
          : findCandidateHintCell(
              SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT,
              attempt,
              puzzle,
              solution,
            )

      // Cannot found a valid hint cell
      if (hintCell === null) return state

      const { r, c } = hintCell
      if (state.hintCell.r === r && state.hintCell.c === c) {
        return { ...state, hintTick: state.hintTick + 1 }
      }

      const v = r >= 0 && c >= 0 ? solution[r][c] : -1
      return { ...state, hintCell: { r, c, v }, hintTick: state.hintTick + 1 }
    }
    case KyokuyaSudokuActionType.INPUT: {
      // Not in running state.
      if (state.gameStatus !== GameRunningStatus.RUNNING) return state

      const v = action.payload
      const SUDOKU_SIZE = state.SUDOKU_SIZE_SQRT ** 2

      // Invalid input
      if (!Number.isInteger(v) || v < -1 || v >= SUDOKU_SIZE) return state

      const { r, c } = state.activatedCell
      if (r < 0 || c < 0) return state

      // Cannot modify the content on the preset cell.
      if (state.puzzle[r][c] !== -1) return state

      // Nothing changed.
      if (state.attempt[r][c] === v) return state

      const {
        SUDOKU_SIZE_SQRT,
        attempt,
        attemptTick,
        duplicatedMap,
        segmentNoMap,
        activatedCell,
      } = state

      // Following two modification is intended.
      attempt[r][c] = v
      patchDuplicatedMap(
        r,
        c,
        duplicatedMap as boolean[][],
        SUDOKU_SIZE_SQRT,
        attempt,
        segmentNoMap,
      )

      return {
        ...state,
        attemptTick: attemptTick + 1,
        activatedCell:
          activatedCell.r === r && activatedCell.c ? activatedCell : { r, c },
      }
    }
    default:
      return state
  }
}
