import PropTypes from 'prop-types'
import React from 'react'
import { KyokuyaSudokuContext } from './context'
import { reducer } from './reducer'
import type { IKyokuyaSudokuState } from './state'
import { initKyokuyaSudokuState } from './state'

export interface IKyokuyaSudokuContextProviderProps {
  /**
   * Initial context data.
   */
  initialState?: Partial<IKyokuyaSudokuState>
  /**
   * Descendant elements.
   */
  children: React.ReactNode
}

export const KyokuyaSudokuContextProvider: React.FC<
  IKyokuyaSudokuContextProviderProps
> = props => {
  const { children, initialState } = props
  const [state, dispatch] = React.useReducer(
    reducer,
    () => ({ ...initialState }),
    initKyokuyaSudokuState,
  )
  const context = React.useMemo(
    () => ({
      ...state,
      dispatch,
    }),
    [state, dispatch],
  )

  return (
    <KyokuyaSudokuContext.Provider value={context}>
      {children}
    </KyokuyaSudokuContext.Provider>
  )
}

KyokuyaSudokuContextProvider.propTypes = {
  initialState: PropTypes.any,
  children: PropTypes.node.isRequired,
}

KyokuyaSudokuContextProvider.displayName = 'KyokuyaSudokuContextProvider'
